select 
a.fecha_ingeg as fecha_egreso,       
a.ide_ingeg as codigo_egreso,      
a.numero_documento_ingeg as numero_documento,       
a.ide_solicitud as codigo_solicitud,       
a.id_maint_work_order as "Orden Trabajo en el Egreso",       
b.id_maint_work_order as "Orden Trabajo en la Solicitud"           
from bodt_ingreso_egreso a                
inner join solicitud_items b on a.ide_solicitud = b.ide_solicitud            
where a.id_maint_work_order!= b.id_maint_work_order ORDER BY 4;
 

/***************************************************************************/

select
b.ide_solicitud,
a.id_maint_work_order as id_maint_work_order_egreso,       
b.id_maint_work_order as id_maint_work_order_solicitud  
from bodt_ingreso_egreso a                
inner join solicitud_items b on a.ide_solicitud = b.ide_solicitud            
where a.id_maint_work_order!= b.id_maint_work_order;


