SELECT * FROM sis_auditoria WHERE fecha_audi BETWEEN fecha_audi >= '2025-04-09 00:00:00' AND fecha_audi <= '2025-07-02 23:59:59'

SELECT substr(sql_audi, 1, 26) AS sql_inicio
FROM sis_auditoria
WHERE fecha_audi BETWEEN '2025-04-09 00:00:00' AND '2025-07-02 23:59:59';
HAVING  substr(sql_audi, 1, 26)  ILIKE '%solicitud_items'

INSERT INTO solicitud_items


SELECT substr(sql_audi, 12, 15) AS sql_inicio
FROM sis_auditoria
WHERE fecha_audi BETWEEN '2025-04-09 00:00:00' AND '2025-07-02 23:59:59'
  AND trim(substr(sql_audi, 12, 15)) = 'INSERT INTO solicitud_items';




SELECT sql_audi FROM sis_auditoria 
WHERE fecha_audi BETWEEN '2025-04-09 00:00:00' AND '2025-07-02 23:59:59'
AND  tabla_audi = 'solicitud_items' 
AND trim(substr(sql_audi, 1, 20)) = '*IDE_SOLICITUD = 76';
--AND sql_audi ILIKE '%76%'
ORDER BY 6


SELECT split_part(sql_audi) FROM sis_auditoria 
WHERE fecha_audi BETWEEN '2025-04-09 00:00:00' AND '2025-07-02 23:59:59'
AND  tabla_audi = 'solicitud_items'


