SELECT 
  split_part(sql_audi, '***', 1) AS datos_antes,
  split_part(sql_audi, '***', 2) AS sentencia_update,
	*	
FROM sis_auditoria 
WHERE fecha_audi BETWEEN '2025-04-09 00:00:00' AND '2025-07-02 23:59:59'
  AND tabla_audi = 'solicitud_items'
	AND trim(substr(sql_audi, 1, 20)) = '*IDE_SOLICITUD = 76';
	--AND trim(substr(sql_audi, 1, 20)) = '*IDE_SOLICITUD = 80';
	--AND trim(substr(sql_audi, 1, 20)) = '*IDE_SOLICITUD = 88';
	
